let bandsData=[],names=[],bandMap={},dataGenerated=null,capitalData={schemaVersion:1,bands:{}},memberData={schemaVersion:1,bands:{}},newsData={schemaVersion:1,articles:[]},curName=null,curYear=null,curCapitalYear=null,curCapitalTrendMetric='revenue-expenses',filt='all',activeProfileTab='overview',activeNewsCommunity=null,newsVisible=9,capitalPromise=null,memberPromise=null,newsPromise=null,restoringRoute=false;
const el=id=>document.getElementById(id);
