function setDocumentMeta(title,description,path){document.title=title;const canonical=new URL(path,SITE_ORIGIN).href;const descriptionNode=document.querySelector('meta[name="description"]');if(descriptionNode)descriptionNode.content=description;const canonicalNode=document.querySelector('link[rel="canonical"]');if(canonicalNode)canonicalNode.href=canonical;[['meta[property="og:title"]','content',title],['meta[property="og:description"]','content',description],['meta[property="og:url"]','content',canonical],['meta[name="twitter:title"]','content',title],['meta[name="twitter:description"]','content',description]].forEach(([selector,attribute,value])=>{const node=document.querySelector(selector);if(node)node.setAttribute(attribute,value)})}
const ISC_FILING=id=>`https://fnp-ppn.aadnc-aandc.gc.ca/fnp/Main/Search/FederalFundingMain.aspx?BAND_NUMBER=${id}&lang=eng`;
const aliases={name:['name','n'],role:['role','r','position'],months:['months','mo','numberOfMonths','number_of_months'],remuneration:['remuneration','re','salary','honoraria'],travel:['travel','travelAndPerDiems','travelPerDiems','travel_and_per_diems'],expenses:['expenses','ex','expense'],creditCard:['creditCard','credit_card','cc'],otherPayments:['otherPayments','other','other_payments','otherPaymentsReceived'],total:['total','t']};
const NEWS_CATEGORIES=['Governance','Elections','Financial','Infrastructure','Housing','Healthcare','Education','Business & Economic Development','Employment','Funding & Grants','Land Claims','Treaties','Environment','Culture & Language','Justice','Emergencies','Community Events','Other'];

function raw(p,k){for(const a of aliases[k]||[k]){if(p&&p[a]!=null&&p[a]!=='')return p[a]}return null}
function parseMoney(v){if(v==null||v==='')return 0;if(typeof v==='number')return Number.isFinite(v)?v:0;const s=String(v).trim();if(!s||s==='-'||s==='—'||/n\/?a/i.test(s))return 0;const neg=/^\(.+\)$/.test(s);const n=Number(s.replace(/[^0-9.\-]/g,''));return Number.isFinite(n)?(neg?-Math.abs(n):n):0}
