function roleOf(p){const r=String(raw(p,'role')||'').toLowerCase();const n=String(raw(p,'name')||'').toLowerCase();if(/chief/.test(r)||/\bchief\b/.test(n))return 'Chief';return 'Councillor'}
function roleKey(p){return roleOf(p).toLowerCase()}
function cleanPeople(f){return ((f&&f.people)||[]).filter(p=>String(raw(p,'name')||'').trim()).map(p=>{let travel=raw(p,'travel'),expenses=raw(p,'expenses'),creditCard=raw(p,'creditCard');if(travel==null&&expenses==null&&creditCard==null&&p.travelExpenses!=null)travel=p.travelExpenses;return{raw:p,name:String(raw(p,'name')||'').trim(),role:roleOf(p),months:raw(p,'months'),remuneration:raw(p,'remuneration'),travel,expenses,creditCard,otherPayments:raw(p,'otherPayments'),total:raw(p,'total')}})}
