function auditedFilingsByYear(band){const by={};auditedFilings(band).forEach(f=>{const y=String(f.year||'');if(!y)return;if(!by[y]||(f.posted&&!by[y].posted)||(f.href&&!by[y].href))by[y]=f});return Object.values(by).sort((a,b)=>String(b.year).localeCompare(String(a.year)))}
function isManualReview(f){const status=String(f&&f.parse_status||'');const confidence=String(f&&f.parse_confidence||'');return Boolean(f&&(f.manual_review_required||status==='pending_manual_review'||status==='sanitized_no_valid_rows'||confidence==='low'||confidence==='manual_review_required'))}
function getFilingStatus(f){if(!f)return{key:'missing',label:'No filing found',color:'red'};if(!f.posted)return{key:'not-posted',label:'Not posted',color:'grey'};if(isManualReview(f))return{key:'review',label:'Manual review needed',color:'red'};if(hasRows(f))return{key:'parsed',label:'Parsed',color:'green'};return{key:'pending',label:'Posted, pending extraction',color:'amber'}}
