function calculateFiscalYearSummary(rows){return{total:sumRows(rows,calculateRowTotal),remuneration:sumRows(rows,p=>parseMoney(p.remuneration)),travelExpenses:sumRows(rows,rowExpenseTravel),other:sumRows(rows,rowOther),officials:rows.length}}
function calculateSpendingComposition(summary){const total=parseMoney(summary&&summary.total);const share=value=>total>0?Math.max(0,(parseMoney(value)/total)*100):0;return{remuneration:share(summary&&summary.remuneration),travelExpenses:share(summary&&summary.travelExpenses),other:share(summary&&summary.other)}}
