function formatNumber(v){const n=Number(v);return Number.isFinite(n)?Math.round(n).toLocaleString('en-CA'):'—'}
function getBandSummary(bandId,fiscalYear){const band=findBand(bandId);if(!band)return null;const filing=remFilingsByYear(band).find(f=>f.year===fiscalYear)||null;return{band,filing,rows:cleanPeople(filing),summary:calculateFiscalYearSummary(cleanPeople(filing)),status:getFilingStatus(filing),sources:getSourceLinks(band,filing)}}
