function getSourceDocuments(bandId){const band=findBand(bandId);return band?[...(band.filings||[])].sort((a,b)=>String(b.year||'').localeCompare(String(a.year||''))||String(a.docType||'').localeCompare(String(b.docType||''))):[]}
function getCapitalParsedYears(band){const years=capitalYearsForBand(band.id);return Object.keys(years).filter(year=>years[year]&&years[year].parseStatus==='parsed'&&years[year].publishable!==false).sort((a,b)=>b.localeCompare(a))}
function getCapitalDisplayYear(band){const years=capitalYearsForBand(band.id),parsed=getCapitalParsedYears(band);if(curCapitalYear&&years[curCapitalYear])return curCapitalYear;if(curYear&&years[curYear])return curYear;return parsed[0]||curYear||null}
