function memberSourceText(bandId){const info=getMemberInfo(bandId);if(!info||!info.sourceUrl)return'';const checked=info.lastChecked?` · checked ${esc(info.lastChecked)}`:'';return`<div class="sc-sub"><a href="${esc(info.sourceUrl)}" target="_blank" rel="noopener">Member count source</a>${checked}</div>`}
function memberOverviewMarkup(bandId){const info=getMemberInfo(bandId),count=memberCountValue(bandId);if(count==null)return'Not available from source';const period=info&&info.sourceYear?` <span class="source-period">(${esc(info.sourceYear)})</span>`:'';return info&&info.sourceUrl?`<a href="${esc(info.sourceUrl)}" target="_blank" rel="noopener">${formatNumber(count)} registered members</a>${period}`:`${formatNumber(count)} registered members${period}`}
function getSourceLinks(band,filing){const statements=band?auditedFilingsByYear(band):[],statement=statements.find(f=>f.year===curYear&&f.href)||statements.find(f=>f.href)||null;return{profile:band?ISC_FILING(band.id):'#',pdf:filing&&filing.href?filing.href:null,auditedStatement:statement&&statement.href?statement.href:null}}
function getProvinceSummary(){const bandIds=new Set(),years=new Set();let rows=0,total=0,parsedFilings=0,pending=0,review=0;bandsData.forEach(b=>remFilingsByYear(b).forEach(f=>{const status=getFilingStatus(f);if(status.key==='parsed'){const parsed=cleanPeople(f);bandIds.add(b.id);years.add(f.year);rows+=parsed.length;total+=sumRows(parsed,calculateRowTotal);parsedFilings++}else if(status.key==='review')review++;else if(status.key==='pending')pending++}));return{tracked:bandsData.length,bandsWithParsed:bandIds.size,rows,total,years:years.size,parsedFilings,pending,review,updated:dataGenerated}}
