async function loadCapitalData(){if(capitalPromise)return capitalPromise;capitalPromise=(async()=>{try{const r=await fetch('/capital-data.json',{cache:'no-store'});if(!r.ok)throw Error('capital data missing');capitalData=await r.json()}catch(e){capitalData={schemaVersion:1,bands:{}}}return capitalData})();return capitalPromise}
