function renderProvinceSummary(s){if(el('provTracked'))el('provTracked').textContent=s.tracked;if(el('provBands'))el('provBands').textContent=s.bandsWithParsed;if(el('provFilings'))el('provFilings').textContent=s.parsedFilings}
function recentTimestamp(band,filing){return filing.reparsed||filing.updated||band.scraped||null}
function renderRecentlyUpdated(){const entries=[];bandsData.forEach(b=>{const filings=remFilingsByYear(b).filter(hasRows),explicit=filings.filter(f=>f.reparsed||f.updated);if(explicit.length)explicit.forEach(f=>entries.push({band:b,filing:f,updated:f.reparsed||f.updated}));else if(filings[0]&&b.scraped)entries.push({band:b,filing:filings[0],updated:b.scraped})});entries.sort((a,b)=>String(b.updated).localeCompare(String(a.updated))||String(b.filing.year).localeCompare(String(a.filing.year)));const chosen=[],seenBands=new Set();for(const entry of entries){if(seenBands.has(entry.band.id))continue;seenBands.add(entry.band.id);chosen.push(entry);if(chosen.length===6)break}el('recentList').innerHTML='';if(!chosen.length){el('recentList').innerHTML='<div class="trend-empty">Recent update metadata will appear after future parsing runs.</div>';return}chosen.forEach(entry=>{const item=document.createElement('div');item.className='recent-item';const status=getFilingStatus(entry.filing);item.innerHTML=`<div class="recent-main"><div class="recent-name">${esc(entry.band.name)}</div><div class="recent-meta">${esc(entry.filing.year)} · ${esc(status.label)} · ${esc(timeAgo(entry.updated))}</div></div><button class="recent-btn">View profile</button>`;item.querySelector('button').onclick=()=>pick(entry.band.name,entry.filing.year);el('recentList').appendChild(item)})}
function renderChips(){el('chips').innerHTML='';let shown=names.filter(n=>remFilings(bandMap[n]||{}).some(isReliableParsed)).slice(0,6);if(!shown.length)shown=names.slice(0,6);shown.forEach(n=>{const d=document.createElement('div');d.className='chip';d.textContent=n;d.onclick=()=>pick(n);el('chips').appendChild(d)})}
function newsArticles(){return (newsData&&newsData.articles||[]).filter(a=>a&&a.title&&a.url&&/^(SK|Saskatchewan)$/i.test(String(a.provinceTerritory||a.province||'SK'))).slice().sort((a,b)=>String(b.publishedAt||'').localeCompare(String(a.publishedAt||'')))}
function newsCommunitySources(){return newsData&&newsData.communitySources||[]}
function newsSourcesForBand(band){return newsCommunitySources().find(source=>String(source.bandId)===String(band.id)||source.communityName===band.name)||null}
function normalizeCommunityName(value){return String(value||'').normalize('NFKD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/&/g,' and ').replace(/['’]/g,'').replace(/\b(first nations?|cree nation|dene nation|dakota nation|nakoda nation|saulteaux nation|indian band)\b/g,' ').replace(/[^a-z0-9]+/g,' ').trim()}
function articleMatchesCommunity(article,band){if(!article||!band)return false;if(article.bandId!=null&&String(article.bandId)===String(band.id))return true;const target=normalizeCommunityName(band.name);if(!target)return false;const identities=[article.communityName,article.community,...(article.communityAliases||[])].map(normalizeCommunityName).filter(Boolean);return identities.includes(target)}
function newsCategory(article){return article.category||'Other'}
