function articleDate(article){if(!article.publishedAt)return'Undated';const raw=String(article.publishedAt),parts=/^(\d{4})-(\d{2})-(\d{2})$/.exec(raw),date=parts?new Date(Number(parts[1]),Number(parts[2])-1,Number(parts[3])):new Date(raw);return Number.isFinite(date.getTime())?date.toLocaleDateString('en-CA',{year:'numeric',month:'short',day:'numeric'}):'Undated'}
