function newsCard(article){const source=article.sourceName||article.publication||'Source',summary=article.summary||'',alts=Array.isArray(article.alternateSources)?article.alternateSources.length:0;return`<article class="news-card"><div class="news-card-body"><div class="news-meta"><span>${esc(article.communityName||'Saskatchewan First Nations')}</span><span>·</span><span>${esc(source)}</span><span>·</span><span>${esc(articleDate(article))}</span></div><h2>${esc(article.title)}</h2><p>${esc(summary)}</p><div class="news-card-actions"><span><span class="news-source-type">${esc(sourceTypeLabel(article))}</span> <span class="news-category">${esc(newsCategory(article))}</span>${alts?` <span class="news-category">${alts+1} sources</span>`:''}</span><a class="small-btn" href="${esc(article.url)}" target="_blank" rel="noopener">Original Source</a></div></div></article>`}
function renderNewsPage(){const grid=el('newsGrid');if(!grid)return;const rows=activeNewsCommunity?filteredNews().filter(article=>articleMatchesCommunity(article,activeNewsCommunity)):filteredNews(),shown=rows.slice(0,newsVisible),heading=el('newsPage').querySelector('.news-hero h1'),intro=el('newsPage').querySelector('.news-hero p');heading.textContent=activeNewsCommunity?`${activeNewsCommunity.name} Updates`:'Saskatchewan Updates';intro.textContent=activeNewsCommunity?`Dated public updates currently indexed for ${activeNewsCommunity.name}.`:'Public updates connected to Saskatchewan First Nations from official community channels, organizations, government releases, and reputable news outlets.';grid.innerHTML=shown.length?shown.map(newsCard).join(''):`<div class="news-empty">${activeNewsCommunity?`No dated public update is indexed for ${esc(activeNewsCommunity.name)} yet.`:'No Saskatchewan public updates are loaded yet.'}</div>`;el('newsMoreBtn').style.display=rows.length>newsVisible?'inline-flex':'none'}
