function setView(view){['provinceOverview','recentSection','empty','results','directoryPage','newsPage'].forEach(id=>{const node=el(id);if(node)node.style.display='none'});if(el('profilePrerender'))el('profilePrerender').hidden=true;if(view==='home'){el('provinceOverview').style.display='';el('recentSection').style.display='';el('empty').style.display=''}else if(view==='profile')el('results').style.display='block';else if(view==='directory')el('directoryPage').style.display='block';else if(view==='news')el('newsPage').style.display='block';document.body.dataset.view=view}
async function showNewsPage(community='',options={}){activeNewsCommunity=community?bandsData.find(b=>b.name===community)||null:null;setView('news');setDocumentMeta('Saskatchewan First Nations News | OpenBand','Recent public updates connected to Saskatchewan First Nations from original community, organization, government, and news sources.','/news/');newsVisible=8;await loadNewsData();renderNewsPage();if(!options.history&&!restoringRoute)history.pushState({page:'news'},'','/news/');if(options.scroll!==false)window.scrollTo({top:el('newsPage').offsetTop-72,behavior:'smooth'})}
function showMainPage(showHomepage=true,options={}){if(showHomepage){setView('home');curName=null;setDocumentMeta('OpenBand Canada | Saskatchewan First Nations Public Financial Records','Search Saskatchewan First Nations public financial records, filing history, and original ISC source documents.','/');if(!options.history&&!restoringRoute)history.pushState({page:'home'},'','/')}else setView('profile')}
function directoryStatus(band){const filings=remFilingsByYear(band),latest=filings[0]||null;if(!latest||!latest.posted)return{key:'none',label:'No filing available'};const status=getFilingStatus(latest);if(status.key==='parsed')return{key:'parsed',label:'Parsed'};if(status.key==='review')return{key:'review',label:'Manual review needed'};return{key:'pending',label:'Pending extraction'}}
function directoryHasCapital(band){return getCapitalParsedYears(band).length>0}
function renderDirectory(){const query=el('directorySearch').value.trim().toLowerCase(),treaty=el('treatyFilter').value,status=el('statusFilter').value,capital=el('capitalFilter').value;const rows=bandsData.filter(band=>{const state=directoryStatus(band),hasCapital=directoryHasCapital(band);return(!query||band.name.toLowerCase().includes(query))&&(!treaty||String(band.treaty||'')===treaty)&&(!status||state.key===status)&&(!capital||(capital==='available')===hasCapital)}).sort((a,b)=>a.name.localeCompare(b.name));el('directoryCount').textContent=`${rows.length} communit${rows.length===1?'y':'ies'}`;el('directoryEmpty').hidden=rows.length>0;const letters=[...new Set(rows.map(b=>b.name.charAt(0).toUpperCase()))];el('azLinks').innerHTML='ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('').map(letter=>letters.includes(letter)?`<a href="#letter-${letter}">${letter}</a>`:`<span aria-hidden="true">${letter}</span>`).join('');const groups=new Map();rows.forEach(b=>{const letter=b.name.charAt(0).toUpperCase();if(!groups.has(letter))groups.set(letter,[]);groups.get(letter).push(b)});el('directoryList').innerHTML=[...groups].map(([letter,bands])=>`<section class="directory-group" id="letter-${letter}"><h2>${letter}</h2><div class="directory-community-list">${bands.map(b=>{const state=directoryStatus(b),capitalText=directoryHasCapital(b)?'Community Capital available':'Capital extraction pending';return`<a class="directory-community" href="${profilePath(b.name)}"><span><strong>${esc(b.name)}</strong><small>${esc(b.treaty||'Treaty not listed')} · ${esc(capitalText)}</small></span><span class="directory-status status-${state.key}">${esc(state.label)}</span></a>`}).join('')}</div></section>`).join('')}
