function renderSourceDocuments(band){band=selectedBand();if(!band)return;const docs=getSourceDocuments(band.id);el('sourcesPanel').dataset.bandId=String(band.id);el('sourcesPanel').innerHTML=`<div class="section-head"><div><h3>Source Documents</h3><p>Original FNFTA records published by Indigenous Services Canada for ${esc(band.name)}.</p></div></div><div class="source-list">${docs.length?docs.map(f=>`<div class="source-row"><div class="source-year">${esc(f.year||'—')}</div><div><div class="source-type">${esc(f.docType||'Public filing')}</div><div class="source-meta">${esc(sourceDocumentStatus(f))}${f.date?` · ${esc(f.date)}`:''}</div></div>${f.href?`<a class="source-link" href="${f.href}" target="_blank" rel="noopener">Review PDF</a>`:'<span class="source-link muted">Unavailable</span>'}</div>`).join(''):'<div class="trend-empty">No source document records are available for this First Nation.</div>'}</div><div class="note"><strong>Verification:</strong> OpenBand links to public source documents where ISC provides a direct PDF. The <a href="${ISC_FILING(band.id)}" target="_blank" rel="noopener">ISC filing page</a> remains the authoritative document index.</div>`}

const inp=el('si'),acl=el('acl');let ai=-1;
inp.addEventListener('input',()=>{const q=inp.value.trim().toLowerCase();acl.innerHTML='';ai=-1;inp.removeAttribute('aria-activedescendant');if(q.length<2){acl.style.display='none';inp.setAttribute('aria-expanded','false');return}const hits=names.filter(n=>n.toLowerCase().includes(q)).slice(0,10);if(!hits.length){acl.style.display='none';inp.setAttribute('aria-expanded','false');return}hits.forEach((n,index)=>{const b=bandMap[n]||{};const d=document.createElement('div');d.className='aci';d.id=`search-option-${index}`;d.setAttribute('role','option');d.setAttribute('aria-selected','false');d.innerHTML=`<span>${esc(n).replace(new RegExp(escapeRegex(q),'gi'),m=>`<strong>${m}</strong>`)}</span><span class="acp">${esc(b.treaty||b.province||'')}</span>`;d.onclick=()=>{inp.value=n;acl.style.display='none';inp.setAttribute('aria-expanded','false');pick(n)};acl.appendChild(d)});acl.style.display='block';inp.setAttribute('aria-expanded','true')});
inp.addEventListener('keydown',e=>{const its=acl.querySelectorAll('.aci');if(e.key==='ArrowDown'){ai=Math.min(ai+1,its.length-1);e.preventDefault()}else if(e.key==='ArrowUp'){ai=Math.max(ai-1,-1);e.preventDefault()}else if(e.key==='Enter'){ai>=0&&its[ai]?its[ai].click():doSearch();acl.style.display='none';inp.setAttribute('aria-expanded','false');return}else if(e.key==='Escape'){acl.style.display='none';inp.setAttribute('aria-expanded','false');return}else return;its.forEach((t,i)=>{const selected=i===ai;t.classList.toggle('sel',selected);t.setAttribute('aria-selected',String(selected))});if(ai>=0)inp.setAttribute('aria-activedescendant',its[ai].id);else inp.removeAttribute('aria-activedescendant')});
document.addEventListener('click',e=>{if(!e.target.closest('.sbox'))acl.style.display='none'});
function doSearch(){const q=inp.value.trim().toLowerCase();if(!q)return;const match=names.find(n=>n.toLowerCase()===q)||names.find(n=>n.toLowerCase().includes(q));match?pick(match,null,{tab:'overview'}):alert(`No match found for "${inp.value}".`)}
async function pick(name,preferredYear=null,options={}){const band=bandMap[name];if(!band)return;showMainPage(false,{history:true});curName=name;filt='all';inp.value=name;setView('profile');setDocumentMeta(`${name} Financial Records | OpenBand`,`Review ${name} public FNFTA filing availability, parsed Chief and Council remuneration, audited statements, and original ISC source documents.`,profilePath(name));el('results').dataset.bandId=String(band.id);['overviewPanel','capitalPanel','sourcesPanel'].forEach(id=>{el(id).innerHTML='';el(id).dataset.bandId=String(band.id)});el('rName').textContent=name;const sources=getSourceLinks(band,null);el('rProfileLink').href=sources.profile;const fs=remFilingsByYear(band);el('yearSel').innerHTML='';fs.forEach(f=>{const o=document.createElement('option');o.value=f.year;o.textContent=`${f.year} (${getFilingStatus(f).label.toLowerCase()})`;el('yearSel').appendChild(o)});const requested=preferredYear&&(fs.find(f=>f.year===preferredYear)||fs.find(f=>String(f.year).startsWith(String(preferredYear))));curYear=requested?requested.year:bestYear(band);curCapitalYear=preferredYear||curYear;if(curYear)el('yearSel').value=curYear;activeProfileTab=VALID_TABS.includes(options.tab)?options.tab:'overview';document.querySelectorAll('.pill').forEach(p=>p.classList.toggle('active',p.textContent==='All'));renderFilingOverview(band);renderYear();await switchProfileTab(activeProfileTab,{history:true});if(el('profilePrerender'))el('profilePrerender').hidden=true;if(!options.history)updateProfileRoute(options.replace?'replace':'push');if(options.scroll!==false)window.scrollTo({top:el('results').offsetTop-72,behavior:'smooth'})}
function renderFilingOverview(band){el('filingOverview').innerHTML='';remFilingsByYear(band).forEach(f=>{const status=getFilingStatus(f),button=document.createElement('button');button.className=`filing-year${f.year===curYear?' active':''}`;button.innerHTML=`<div class="fy-year">${esc(f.year)}</div><div class="fy-status"><span class="fy-dot ${status.color}"></span>${esc(status.label)}</div>`;button.onclick=()=>{curYear=f.year;el('yearSel').value=f.year;renderYear();renderActiveProfilePanel();updateProfileRoute('push')};el('filingOverview').appendChild(button)})}
function onYearChange(){curYear=el('yearSel').value||null;renderYear();renderActiveProfilePanel();updateHeaderSource();updateProfileRoute('push')}
function currentFiling(){const band=selectedBand();return band?remFilingsByYear(band).find(f=>f.year===curYear):null}
function addStatusTag(text,color){const tag=document.createElement('span');tag.className=`mt ${color}`;tag.textContent=text;el('rMeta').appendChild(tag)}
function renderYear(){const band=selectedBand();if(!band)return;const filing=currentFiling(),rows=cleanPeople(filing),sources=getSourceLinks(band,filing);el('rLink').href=sources.pdf||sources.profile;el('rLink').textContent=sources.pdf?'Source PDF':'ISC profile';el('dataPanel').style.display=rows.length?'':'none';el('pendingPanel').style.display=rows.length?'none':'';el('csvBtn').disabled=!rows.length;el('citeBtn').disabled=!filing;renderFilingOverview(band);renderTrends(band,rows.length?el('trendPanel'):el('pendingTrendPanel'));if(rows.length){const summary=calculateFiscalYearSummary(rows);renderSummary(summary);renderComposition(summary);renderContext(filing,rows,summary);renderT();renderNote(filing,band)}else renderPending(filing,band);updateProfileMeta();updateHeaderSource()}
function renderSummary(s){el('sTotal').textContent=formatMoney(s.total);el('sRemun').textContent=formatMoney(s.remuneration);el('sExp').textContent=formatMoney(s.travelExpenses);el('sOther').textContent=formatMoney(s.other);el('sCount').textContent=s.officials}
function renderComposition(summary){const shares=calculateSpendingComposition(summary);const items=[['Remuneration',shares.remuneration,'bar-rem'],['Travel / Expenses',shares.travelExpenses,'bar-exp'],['Other',shares.other,'bar-other']];el('composition').innerHTML=items.map(([label,value,cls])=>`<div class="composition-row"><div class="composition-label">${label}</div><div class="bar-track"><div class="bar-fill ${cls}" style="width:${Math.min(100,value).toFixed(1)}%"></div></div><div class="composition-pct">${Number.isFinite(value)?value.toFixed(1):'0.0'}%</div></div>`).join('')}
function totalsReconcile(rows){return rows.every(row=>{const components=parseMoney(row.remuneration)+rowExpenseTravel(row)+rowOther(row),total=calculateRowTotal(row);return!total||Math.abs(total-components)<=Math.max(5,total*.04)})}
function renderContext(filing,rows,summary){const notes=[];if(isManualReview(filing))notes.push({text:'Manual review recommended for this filing.',review:true});if(!totalsReconcile(rows)||(filing&&filing.warnings||[]).some(w=>/reconcile|does not (equal|match)/i.test(w)))notes.push({text:'Reported totals do not fully reconcile with the parsed component fields.',review:true});if(rows.some(p=>parseMoney(p.months)>0&&parseMoney(p.months)<12))notes.push({text:'One or more officials are reported with fewer than 12 months served.'});if(summary.other>0)notes.push({text:'Other payments are reported in this filing.'});const largest=summary.travelExpenses>=summary.other&&summary.travelExpenses>0?'Travel / expenses':summary.other>0?'Other payments':null;if(largest)notes.push({text:`${largest} are the largest non-remuneration category for this year.`});if(!notes.length)notes.push({text:'No additional data availability indicators were generated for this filing.'});el('contextList').innerHTML=notes.map(n=>`<div class="context-item${n.review?' review':''}">${esc(n.text)}</div>`).join('')}
function changeMarkup(value){if(value==null||!Number.isFinite(value))return'<span class="change flat">—</span>';const cls=value>0.05?'up':value<-.05?'down':'flat';return`<span class="change ${cls}">${value>0?'+':''}${value.toFixed(1)}%</span>`}
function renderTrends(band,target){const trend=getBandTrend(band.id);if(trend.length<2){target.innerHTML='<div class="trend-empty">Historical trend data will appear once multiple fiscal years are parsed.</div>';return}const enriched=trend.map((row,index)=>({...row,changes:index?{total:calculateYearOverYearChange(row.total,trend[index-1].total),remuneration:calculateYearOverYearChange(row.remuneration,trend[index-1].remuneration),travelExpenses:calculateYearOverYearChange(row.travelExpenses,trend[index-1].travelExpenses),other:calculateYearOverYearChange(row.other,trend[index-1].other),officials:calculateYearOverYearChange(row.officials,trend[index-1].officials)}:null})).reverse();target.innerHTML=`<div class="tw"><table class="trend-table"><thead><tr><th>Fiscal year</th><th>Total paid</th><th>Remuneration</th><th>Travel / Expenses</th><th>Other</th><th>Officials</th></tr></thead><tbody>${enriched.map(row=>`<tr><td class="trend-year">${esc(row.year)}${row.status.key==='review'?' <span class="change flat">review</span>':''}</td><td>${formatMoney(row.total)} ${row.changes?changeMarkup(row.changes.total):''}</td><td>${formatMoney(row.remuneration)} ${row.changes?changeMarkup(row.changes.remuneration):''}</td><td>${formatMoney(row.travelExpenses)} ${row.changes?changeMarkup(row.changes.travelExpenses):''}</td><td>${formatMoney(row.other)} ${row.changes?changeMarkup(row.changes.other):''}</td><td>${row.officials} ${row.changes?changeMarkup(row.changes.officials):''}</td></tr>`).join('')}</tbody></table></div>`}
function setF(f,btn){filt=f;document.querySelectorAll('.pill').forEach(p=>p.classList.remove('active'));btn.classList.add('active');renderT()}
function visibleRows(){let rows=cleanPeople(currentFiling());if(filt!=='all')rows=rows.filter(p=>roleKey(p)===filt);const sort=el('sortSel').value;if(sort==='td')rows.sort((a,b)=>calculateRowTotal(b)-calculateRowTotal(a));else if(sort==='ta')rows.sort((a,b)=>calculateRowTotal(a)-calculateRowTotal(b));else rows.sort((a,b)=>a.name.localeCompare(b.name));return rows}
function renderT(){const rows=visibleRows();if(!rows.length){el('tb').innerHTML='<tr><td colspan="7" style="text-align:center;color:var(--muted)">No rows match this filter.</td></tr>';el('tfl').textContent='0 members shown';el('tft').textContent='Total: $0';return}el('tb').innerHTML=rows.map(p=>`<tr class="leadership-row" tabindex="0" aria-expanded="false" onclick="toggleMobileRow(event,this)" onkeydown="toggleMobileRowKey(event,this)"><td data-label="Name"><div class="tn">${esc(p.name)}</div></td><td data-label="Role"><span class="rb ${p.role==='Chief'?'rc':'rco'}">${esc(p.role)}</span></td><td data-label="Months" style="font-size:13px;color:var(--muted)">${p.months!=null&&p.months!==''?esc(p.months):'&mdash;'}</td><td data-label="Remuneration" class="amt">${money(p.remuneration)}</td><td data-label="Travel / expenses" class="amt">${money(rowExpenseTravel(p))}</td><td data-label="Other" class="amt">${money(rowOther(p))}</td><td data-label="Total" class="amtt">${formatMoney(calculateRowTotal(p))}</td></tr>`).join('');el('tfl').textContent=`${rows.length} member${rows.length!==1?'s':''} shown`;el('tft').textContent=`Total: ${formatMoney(sumRows(rows,calculateRowTotal))}`}
function toggleMobileRow(event,row){if(!window.matchMedia('(max-width:560px)').matches||event.target.closest('a,button,select'))return;const expanded=row.classList.toggle('expanded');row.setAttribute('aria-expanded',String(expanded))}
function toggleMobileRowKey(event,row){if(event.key!=='Enter'&&event.key!==' ')return;event.preventDefault();toggleMobileRow(event,row)}
function methodName(status){const s=String(status||'');if(s.startsWith('ok_openai'))return'OpenAI-assisted PDF extraction';if(s.startsWith('ok_pdf_keyword_table'))return'keyword-aware PDF table extraction';if(s.startsWith('ok_pdf_text'))return'PDF text extraction';if(s.startsWith('ok_pdfplumber'))return'PDF table extraction';if(s.startsWith('manual_'))return'manually reviewed transcription';return'automated extraction'}
function renderNote(filing,band){const status=getFilingStatus(filing),sources=getSourceLinks(band,filing);el('srcNote').innerHTML=`<strong>Source:</strong> ${esc(status.label)} from the Schedule of Remuneration and Expenses published by ISC using ${esc(methodName(filing.parse_status))}. <strong>Data availability:</strong> source documents use different column labels, so OpenBand groups travel and expense categories while keeping other payments separate. <strong>Verification:</strong> review the <a href="${sources.pdf||sources.profile}" target="_blank" rel="noopener">${sources.pdf?'original PDF':'ISC profile page'}</a> before publication.`}
function renderPending(filing,band){const parsed=remFilingsByYear(band).filter(hasRows)[0],status=getFilingStatus(filing),sources=getSourceLinks(band,filing);el('pendingTitle').textContent=status.label;if(status.key==='not-posted')el('pendingMsg').innerHTML=`The ${esc(curYear)} remuneration schedule is not posted to ISC yet.${parsed?` Parsed data is available for ${esc(parsed.year)} from the fiscal year menu.`:''}`;else if(status.key==='review')el('pendingMsg').innerHTML=`The ${esc(curYear)} public filing needs manual review before OpenBand treats it as parsed data. <a href="${sources.pdf||sources.profile}" target="_blank" rel="noopener">Review the source document</a>.`;else el('pendingMsg').innerHTML=`A public filing exists for ${esc(curYear)}, but no rows have been extracted yet.${parsed?` The newest parsed year is ${esc(parsed.year)}. `:' '}<a href="${sources.pdf||sources.profile}" target="_blank" rel="noopener">Review the source document</a>.`}
function csvEscape(v){const s=String(v==null?'':v);return/[",\n]/.test(s)?`"${s.replace(/"/g,'""')}"`:s}
function exportCSV(){const filing=currentFiling(),rows=visibleRows();if(!filing||!rows.length)return;const source=getSourceLinks(bandMap[curName],filing).pdf||getSourceLinks(bandMap[curName],filing).profile;const header=['band','fiscal_year','name','role','months','remuneration','travel_expenses','other','total','source_url'];const body=rows.map(p=>[curName,curYear,p.name,p.role,p.months||'',parseMoney(p.remuneration),rowExpenseTravel(p),rowOther(p),calculateRowTotal(p),source].map(csvEscape).join(','));const blob=new Blob([[header.join(','),...body].join('\n')],{type:'text/csv;charset=utf-8'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`openband-${curName}-${curYear}.csv`.replace(/[^a-z0-9._-]+/gi,'-').toLowerCase();document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(a.href)}
async function copyCitation(){const filing=currentFiling();if(!filing)return;const url=getSourceLinks(bandMap[curName],filing).pdf||getSourceLinks(bandMap[curName],filing).profile,citation=`OpenBand, "${curName} Chief and Council remuneration, fiscal year ${curYear}." Data organized from an Indigenous Services Canada FNFTA public filing. Source document: ${url}. Accessed ${new Date().toISOString().slice(0,10)}.`;try{await navigator.clipboard.writeText(citation);el('citeBtn').textContent='Citation copied';setTimeout(()=>el('citeBtn').textContent='Copy citation',1600)}catch(e){prompt('Copy citation',citation)}}
async function copyProfileLink(){if(!curName)return;const url=new URL(profileUrl(),SITE_ORIGIN).href;try{await navigator.clipboard.writeText(url);el('shareBtn').textContent='Profile link copied';setTimeout(()=>el('shareBtn').textContent='Copy profile link',1600)}catch(e){prompt('Copy profile link',url)}}
function compactTrendSection({panelId=null,containerId=null,title,subtitle}){const panel=panelId?el(panelId):null,container=containerId?el(containerId):null,section=panel?panel.closest('.trend-wrap'):container&&container.querySelector('.trend-wrap');if(!section||section.tagName==='DETAILS')return;const details=document.createElement('details'),summary=document.createElement('summary'),body=document.createElement('div'),head=section.querySelector(':scope > .section-head'),tools=head&&head.querySelector('.capital-trend-tools');details.className='disclosure';summary.innerHTML=`<span><span class="disclosure-title">${esc(title)}</span><span class="disclosure-sub">${esc(subtitle)}</span></span>`;body.className='disclosure-body';if(tools)body.appendChild(tools);[...section.children].filter(child=>child!==head).forEach(child=>body.appendChild(child));details.append(summary,body);section.replaceWith(details)}
